  1	import * as React from 'react';
  2	import { useCallback, useEffect } from 'react';
  3	import { getName, getNamespace } from '@odf/shared/selectors';
  4	import {
  5	  K8sResourceCommon,
  6	  useModal,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
  9	import * as _ from 'lodash-es';
 10	import { TFunction } from 'react-i18next';
 11	import { useNavigate } from 'react-router-dom-v5-compat';
 12	import {
 13	  Dropdown,
 14	  DropdownItem,
 15	  DropdownPopperProps,
 16	  MenuToggle,
 17	  Tooltip,
 18	} from '@patternfly/react-core';
 19	import { EllipsisVIcon } from '@patternfly/react-icons';
 20	import { useAccessReview } from '../hooks/rbac-hook';
 21	import { ModalKeys, defaultModalMap } from '../modals/types';
 22	import { useCustomTranslation } from '../useCustomTranslationHook';
 23	import { referenceForModel } from '../utils';
 24	
 25	const useClickOutside = (
 26	  dropdownRef: React.RefObject<HTMLElement>,
 27	  dropdownToggleRef: React.RefObject<HTMLElement>,
 28	  callback: () => void
 29	) => {
 30	  useEffect(() => {
 31	    const handleClickOutside = (event: MouseEvent) => {
 32	      // Dropdown and its toggle button are 2 separate elements at the same
 33	      // nesting level, so we check that we're interacting outside both.
 34	      if (
 35	        dropdownRef.current &&
 36	        !dropdownRef.current.contains(event.target as Node) &&
 37	        dropdownToggleRef.current &&
 38	        !dropdownToggleRef.current.contains(event.target as Node)
 39	      ) {
 40	        callback();
 41	      }
 42	    };
 43	
 44	    const handleEscapeKey = (event: KeyboardEvent) => {
 45	      if (event.key === 'Escape') {
 46	        callback();
 47	      }
 48	    };
 49	
 50	    document.addEventListener('mousedown', handleClickOutside);
 51	    document.addEventListener('keydown', handleEscapeKey);
 52	    return () => {
 53	      document.removeEventListener('mousedown', handleClickOutside);
 54	      document.removeEventListener('keydown', handleEscapeKey);
 55	    };
 56	  }, [dropdownRef, dropdownToggleRef, callback]);
 57	};
 58	
 59	export type CustomKebabItem = {
 60	  key: string;
 61	  value: string;
 62	  isDisabled?: boolean;
 63	  description?: React.ReactNode;
 64	  component?: React.LazyExoticComponent<any>;
 65	  redirect?: string;
 66	};
 67	
 68	type CustomKebabItemsMap = {
 69	  [key in string]: CustomKebabItem;
 70	};
 71	
 72	type KebabProps = {
 73	  extraProps: {
 74	    resource: K8sResourceCommon;
 75	    resourceModel: K8sModel;
 76	    [key: string]: any;
 77	    forceDeletion?: boolean;
 78	  };
 79	  customKebabItems?: CustomKebabItem[];
 80	  toggleType?: 'Kebab' | 'Dropdown';
 81	  isDisabled?: boolean;
 82	  customActionMap?: {
 83	    [key: string]: () => void;
 84	  };
 85	  terminatingTooltip?: React.ReactNode;
 86	  hideItems?: ModalKeys[];
 87	  customLabel?: string;
 88	  'data-test'?: string;
 89	};
 90	
 91	type KebabStaticProperties = {
 92	  columnClass?: string;
 93	};
 94	
 95	const defaultKebabItems = (t: TFunction, resourceLabel: string) => ({
 96	  [ModalKeys.EDIT_LABELS]: (
 97	    <DropdownItem
 98	      key={ModalKeys.EDIT_LABELS}
 99	      id={ModalKeys.EDIT_LABELS}
100	      data-test-action="Edit labels"
101	    >
102	      {t('Edit labels')}
103	    </DropdownItem>
104	  ),
105	  [ModalKeys.EDIT_ANN]: (
106	    <DropdownItem
107	      key={ModalKeys.EDIT_ANN}
108	      id={ModalKeys.EDIT_ANN}
109	      data-test-action="Edit annotations"
110	    >
111	      {t('Edit annotations')}
112	    </DropdownItem>
113	  ),
114	  [ModalKeys.EDIT_RES]: (
115	    <DropdownItem
116	      key={ModalKeys.EDIT_RES}
117	      id={ModalKeys.EDIT_RES}
118	      data-test-action={`Edit ${resourceLabel}`}
119	    >
120	      {t('Edit {{resourceLabel}}', { resourceLabel })}
121	    </DropdownItem>
122	  ),
123	  [ModalKeys.DELETE]: (
124	    <DropdownItem
125	      key={ModalKeys.DELETE}
126	      id={ModalKeys.DELETE}
127	      data-test-action={`Delete ${resourceLabel}`}
128	    >
129	      {t('Delete {{resourceLabel}}', { resourceLabel })}
130	    </DropdownItem>
131	  ),
132	});
133	
134	export const Kebab: React.FC<KebabProps> & KebabStaticProperties = ({
135	  extraProps,
136	  customKebabItems,
137	  toggleType = 'Kebab',
138	  isDisabled,
139	  terminatingTooltip,
140	  hideItems,
141	  customLabel,
142	  'data-test': dataTestId,
143	}) => {
144	  const { t } = useCustomTranslation();
145	  const launchModal = useModal();
146	  const eventRef = React.useRef(undefined);
147	  const dropdownRef = React.useRef();
148	  const dropdownToggleRef = React.useRef();
149	  const [toggleDirection, setToggleDirection] =
150	    React.useState<DropdownPopperProps['direction']>('down');
151	  const [isOpen, setOpen] = React.useState(false);
152	  const closeDropdown = useCallback(() => setOpen(false), []);
153	
154	  // Use the custom hook to detect clicks outside the Kebab menu
155	  useClickOutside(dropdownRef, dropdownToggleRef, closeDropdown);
156	
157	  const { resourceModel, resource } = extraProps;
158	  const resourceLabel = customLabel ?? resourceModel.label;
159	  const navigate = useNavigate();
160	
161	  const [canCreate, createLoading] = useAccessReview({
162	    group: resourceModel?.apiGroup,
163	    resource: resourceModel?.plural,
164	    name: getName(resource),
165	    ...(!!resourceModel?.namespaced
166	      ? { namespace: getNamespace(resource) }
167	      : {}),
168	    verb: 'create',
169	  });
170	
171	  const showPermissionTooltip = !canCreate && !createLoading;
172	
173	  React.useLayoutEffect(() => {
174	    const e = eventRef.current;
175	    if (toggleType === 'Kebab' && !!e) {
176	      const clientY = e?.clientY; // y-coordinate of kebab button onclick
177	      const clientHeight = e?.target?.nextSibling?.clientHeight; // height of popper menu, which is a sibling of kebab button
178	      const windowHeight =
179	        document.getElementsByTagName('body')[0].clientHeight; // height of viewport
180	
181	      if (clientY + clientHeight >= windowHeight) setToggleDirection('up');
182	      else setToggleDirection('down');
183	    }
184	    // eslint-disable-next-line react-hooks/exhaustive-deps
185	  }, [eventRef.current, toggleType]);
186	
187	  const customKebabItemsMap: CustomKebabItemsMap = React.useMemo(
188	    () =>
189	      customKebabItems
190	        ? customKebabItems?.reduce(
191	            (acc, item) => ({ ...acc, [item.key]: item }),
192	            {}
193	          )
194	        : {},
195	    [customKebabItems]
196	  );
197	
198	  const onClick = (event?: React.SyntheticEvent<HTMLDivElement>) => {
199	    setOpen(false);
200	    const modalComponentProps = { extraProps, isOpen: true };
201	    const actionKey = event.currentTarget.id;
202	    const modalComponent =
203	      customKebabItemsMap[actionKey]?.component || defaultModalMap[actionKey];
204	    const redirectLink = customKebabItemsMap[actionKey]?.redirect;
205	    if (actionKey === ModalKeys.EDIT_RES && !customKebabItemsMap?.[actionKey]) {
206	      const editPrefix = extraProps?.cluster
207	        ? `/odf/edit/${extraProps?.cluster}`
208	        : '/k8s';
209	      let basePath = resourceModel?.namespaced
210	        ? `${editPrefix}/ns/${resource?.metadata?.namespace}`
211	        : `${editPrefix}/cluster`;
212	      navigate(
213	        `${basePath}/${referenceForModel(resourceModel)}/${
214	          resource?.metadata?.name
215	        }/yaml`
216	      );
217	    } else if (redirectLink) {
218	      navigate(redirectLink);
219	    } else {
220	      launchModal(modalComponent, modalComponentProps);
221	    }
222	  };
223	
224	  const dropdownItems = React.useMemo(() => {
225	    const defaultResolved = defaultKebabItems(t, resourceLabel);
226	    const filteredDefaultItems = hideItems
227	      ? Object.keys(defaultResolved)
228	          .filter((key) => !hideItems.includes(key as ModalKeys))
229	          .reduce((obj, key) => {
230	            obj[key] = defaultResolved[key];
231	            return obj;
232	          }, {})
233	      : defaultResolved;
234	    const customResolved: CustomKebabItemsMap = customKebabItemsMap
235	      ? customKebabItemsMap
236	      : {};
237	    const { overrides, custom } = Object.entries(customResolved).reduce(
238	      (acc, [k, obj]) => {
239	        if (hideItems?.includes(k as ModalKeys)) {
240	          return acc;
241	        }
242	        const dropdownItem = (
243	          <DropdownItem
244	            key={k}
245	            id={k}
246	            data-test-action={obj?.value}
247	            isDisabled={obj?.isDisabled}
248	            description={obj?.description}
249	          >
250	            {obj?.value}
251	          </DropdownItem>
252	        );
253	
254	        if (
255	          [
256	            ModalKeys.EDIT_LABELS,
257	            ModalKeys.EDIT_ANN,
258	            ModalKeys.DELETE,
259	            ModalKeys.EDIT_RES,
260	          ].includes(k as ModalKeys)
261	        ) {
262	          acc['overrides'][k] = dropdownItem;
263	        } else {
264	          acc['custom'][k] = dropdownItem;
265	        }
266	        return acc;
267	      },
268	      { overrides: {}, custom: {} }
269	    );
270	    const defaultItems = Object.values(
271	      Object.assign(filteredDefaultItems, overrides)
272	    );
273	
274	    const customItems = Object.values(custom) ?? [];
275	
276	    return [...customItems, ...defaultItems];
277	  }, [t, customKebabItemsMap, resourceLabel, hideItems]);
278	
279	  isDisabled =
280	    isDisabled ||
281	    (!extraProps?.forceDeletion &&
282	      _.has(resource?.metadata, 'deletionTimestamp')) ||
283	    !canCreate;
284	
285	  const content = _.has(resource?.metadata, 'deletionTimestamp')
286	    ? terminatingTooltip || t('Resource is being deleted.')
287	    : '';
288	
289	  return (
290	    <Tooltip
291	      content={
292	        showPermissionTooltip
293	          ? t('You do not have permission to perform this action')
294	          : content
295	      }
296	      trigger={
297	        showPermissionTooltip || (isDisabled && content)
298	          ? 'mouseenter'
299	          : 'manual'
300	      }
301	    >
302	      <Dropdown
303	        data-test={dataTestId || 'kebab-button'}
304	        onSelect={onClick}
305	        ref={dropdownRef}
306	        toggle={{
307	          toggleNode: (
308	            <MenuToggle
309	              ref={dropdownToggleRef}
310	              aria-label="Dropdown toggle"
311	              variant={toggleType === 'Kebab' ? 'plain' : 'default'}
312	              onClick={() => setOpen(!isOpen)}
313	              isExpanded={isOpen}
314	              data-test={dataTestId || 'kebab-button'}
315	              isDisabled={isDisabled}
316	            >
317	              {toggleType === 'Kebab' ? <EllipsisVIcon /> : t('Actions')}
318	            </MenuToggle>
319	          ),
320	          toggleRef: dropdownToggleRef,
321	        }}
322	        isOpen={isOpen}
323	        data-test-id={dataTestId || 'kebab-button'}
324	        popperProps={{
325	          preventOverflow: true,
326	          direction: toggleDirection,
327	          enableFlip: true,
328	          position: 'right',
329	        }}
330	        shouldFocusFirstItemOnOpen={false}
331	      >
332	        {dropdownItems}
333	      </Dropdown>
334	    </Tooltip>
335	  );
336	};
337	
338	Kebab.columnClass = 'dropdown-kebab-pf pf-v6-c-table__action pf-v6-u-min-width';

