  1	import * as React from 'react';
  2	import { useCallback, useEffect } from 'react';
  3	import { getName, getNamespace } from '@odf/shared/selectors';
  4	import {
  5	  K8sResourceCommon,
  6	  useModal,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
  9	import * as _ from 'lodash-es';
 10	import { TFunction } from 'react-i18next';
 11	import { useNavigate } from 'react-router-dom-v5-compat';
 12	import {
 13	  Dropdown,
 14	  DropdownItem,
 15	  DropdownList,
 16	  MenuToggle,
 17	  Tooltip,
 18	} from '@patternfly/react-core';
 19	import { EllipsisVIcon } from '@patternfly/react-icons';
 20	import { useAccessReview } from '../hooks/rbac-hook';
 21	import { ModalKeys, defaultModalMap } from '../modals/types';
 22	import { useCustomTranslation } from '../useCustomTranslationHook';
 23	import { referenceForModel } from '../utils';
 24	
 25	const useClickOutside = (
 26	  dropdownRef: React.RefObject<HTMLElement>,
 27	  dropdownToggleRef: React.RefObject<HTMLElement>,
 28	  callback: () => void
 29	) => {
 30	  useEffect(() => {
 31	    const handleClickOutside = (event: MouseEvent) => {
 32	      // Dropdown and its toggle button are 2 separate elements at the same
 33	      // nesting level, so we check that we're interacting outside both.
 34	      if (
 35	        dropdownRef.current &&
 36	        !dropdownRef.current.contains(event.target as Node) &&
 37	        dropdownToggleRef.current &&
 38	        !dropdownToggleRef.current.contains(event.target as Node)
 39	      ) {
 40	        callback();
 41	      }
 42	    };
 43	
 44	    const handleEscapeKey = (event: KeyboardEvent) => {
 45	      if (event.key === 'Escape') {
 46	        callback();
 47	      }
 48	    };
 49	
 50	    document.addEventListener('mousedown', handleClickOutside);
 51	    document.addEventListener('keydown', handleEscapeKey);
 52	    return () => {
 53	      document.removeEventListener('mousedown', handleClickOutside);
 54	      document.removeEventListener('keydown', handleEscapeKey);
 55	    };
 56	  }, [dropdownRef, dropdownToggleRef, callback]);
 57	};
 58	
 59	export type CustomKebabItem = {
 60	  key: string;
 61	  value: string;
 62	  isDisabled?: boolean;
 63	  description?: React.ReactNode;
 64	  component?: React.LazyExoticComponent<any>;
 65	  redirect?: string;
 66	};
 67	
 68	type CustomKebabItemsMap = {
 69	  [key in string]: CustomKebabItem;
 70	};
 71	
 72	type KebabProps = {
 73	  extraProps: {
 74	    resource: K8sResourceCommon;
 75	    resourceModel: K8sModel;
 76	    [key: string]: any;
 77	    forceDeletion?: boolean;
 78	  };
 79	  customKebabItems?: CustomKebabItem[];
 80	  toggleType?: 'Kebab' | 'Dropdown';
 81	  isDisabled?: boolean;
 82	  customActionMap?: {
 83	    [key: string]: () => void;
 84	  };
 85	  terminatingTooltip?: React.ReactNode;
 86	  hideItems?: ModalKeys[];
 87	  customLabel?: string;
 88	  'data-test'?: string;
 89	};
 90	
 91	type KebabStaticProperties = {
 92	  columnClass?: string;
 93	};
 94	
 95	const defaultKebabItems = (t: TFunction, resourceLabel: string) => ({
 96	  [ModalKeys.EDIT_LABELS]: (
 97	    <DropdownItem
 98	      key={ModalKeys.EDIT_LABELS}
 99	      id={ModalKeys.EDIT_LABELS}
100	      data-test-action="Edit labels"
101	    >
102	      {t('Edit labels')}
103	    </DropdownItem>
104	  ),
105	  [ModalKeys.EDIT_ANN]: (
106	    <DropdownItem
107	      key={ModalKeys.EDIT_ANN}
108	      id={ModalKeys.EDIT_ANN}
109	      data-test-action="Edit annotations"
110	    >
111	      {t('Edit annotations')}
112	    </DropdownItem>
113	  ),
114	  [ModalKeys.EDIT_RES]: (
115	    <DropdownItem
116	      key={ModalKeys.EDIT_RES}
117	      id={ModalKeys.EDIT_RES}
118	      data-test-action={`Edit ${resourceLabel}`}
119	    >
120	      {t('Edit {{resourceLabel}}', { resourceLabel })}
121	    </DropdownItem>
122	  ),
123	  [ModalKeys.DELETE]: (
124	    <DropdownItem
125	      key={ModalKeys.DELETE}
126	      id={ModalKeys.DELETE}
127	      data-test-action={`Delete ${resourceLabel}`}
128	    >
129	      {t('Delete {{resourceLabel}}', { resourceLabel })}
130	    </DropdownItem>
131	  ),
132	});
133	
134	export const Kebab: React.FC<KebabProps> & KebabStaticProperties = ({
135	  extraProps,
136	  customKebabItems,
137	  toggleType = 'Kebab',
138	  isDisabled,
139	  terminatingTooltip,
140	  hideItems,
141	  customLabel,
142	  'data-test': dataTestId,
143	}) => {
144	  const { t } = useCustomTranslation();
145	  const launchModal = useModal();
146	  const dropdownRef = React.useRef();
147	  const dropdownToggleRef = React.useRef();
148	  const [isOpen, setOpen] = React.useState(false);
149	  const closeDropdown = useCallback(() => setOpen(false), []);
150	
151	  // Use the custom hook to detect clicks outside the Kebab menu
152	  useClickOutside(dropdownRef, dropdownToggleRef, closeDropdown);
153	
154	  const { resourceModel, resource } = extraProps;
155	  const resourceLabel = customLabel ?? resourceModel.label;
156	  const navigate = useNavigate();
157	
158	  const [canCreate, createLoading] = useAccessReview({
159	    group: resourceModel?.apiGroup,
160	    resource: resourceModel?.plural,
161	    name: getName(resource),
162	    ...(!!resourceModel?.namespaced
163	      ? { namespace: getNamespace(resource) }
164	      : {}),
165	    verb: 'create',
166	  });
167	
168	  const showPermissionTooltip = !canCreate && !createLoading;
169	
170	  const customKebabItemsMap: CustomKebabItemsMap = React.useMemo(
171	    () =>
172	      customKebabItems
173	        ? customKebabItems?.reduce(
174	            (acc, item) => ({ ...acc, [item.key]: item }),
175	            {}
176	          )
177	        : {},
178	    [customKebabItems]
179	  );
180	
181	  const onClick = (event?: React.SyntheticEvent<HTMLDivElement>) => {
182	    setOpen(false);
183	    const modalComponentProps = { extraProps, isOpen: true };
184	    const actionKey = event.currentTarget.id;
185	    const modalComponent =
186	      customKebabItemsMap[actionKey]?.component || defaultModalMap[actionKey];
187	    const redirectLink = customKebabItemsMap[actionKey]?.redirect;
188	    if (actionKey === ModalKeys.EDIT_RES && !customKebabItemsMap?.[actionKey]) {
189	      const editPrefix = extraProps?.cluster
190	        ? `/odf/edit/${extraProps?.cluster}`
191	        : '/k8s';
192	      let basePath = resourceModel?.namespaced
193	        ? `${editPrefix}/ns/${resource?.metadata?.namespace}`
194	        : `${editPrefix}/cluster`;
195	      navigate(
196	        `${basePath}/${referenceForModel(resourceModel)}/${
197	          resource?.metadata?.name
198	        }/yaml`
199	      );
200	    } else if (redirectLink) {
201	      navigate(redirectLink);
202	    } else {
203	      launchModal(modalComponent, modalComponentProps);
204	    }
205	  };
206	
207	  const dropdownItems = React.useMemo(() => {
208	    const defaultResolved = defaultKebabItems(t, resourceLabel);
209	    const filteredDefaultItems = hideItems
210	      ? Object.keys(defaultResolved)
211	          .filter((key) => !hideItems.includes(key as ModalKeys))
212	          .reduce((obj, key) => {
213	            obj[key] = defaultResolved[key];
214	            return obj;
215	          }, {})
216	      : defaultResolved;
217	    const customResolved: CustomKebabItemsMap = customKebabItemsMap
218	      ? customKebabItemsMap
219	      : {};
220	    const { overrides, custom } = Object.entries(customResolved).reduce(
221	      (acc, [k, obj]) => {
222	        if (hideItems?.includes(k as ModalKeys)) {
223	          return acc;
224	        }
225	        const dropdownItem = (
226	          <DropdownItem
227	            key={k}
228	            id={k}
229	            data-test-action={obj?.value}
230	            isDisabled={obj?.isDisabled}
231	            description={obj?.description}
232	          >
233	            {obj?.value}
234	          </DropdownItem>
235	        );
236	
237	        if (
238	          [
239	            ModalKeys.EDIT_LABELS,
240	            ModalKeys.EDIT_ANN,
241	            ModalKeys.DELETE,
242	            ModalKeys.EDIT_RES,
243	          ].includes(k as ModalKeys)
244	        ) {
245	          acc['overrides'][k] = dropdownItem;
246	        } else {
247	          acc['custom'][k] = dropdownItem;
248	        }
249	        return acc;
250	      },
251	      { overrides: {}, custom: {} }
252	    );
253	    const defaultItems = Object.values(
254	      Object.assign(filteredDefaultItems, overrides)
255	    );
256	
257	    const customItems = Object.values(custom) ?? [];
258	
259	    return [...customItems, ...defaultItems];
260	  }, [t, customKebabItemsMap, resourceLabel, hideItems]);
261	
262	  isDisabled =
263	    isDisabled ||
264	    (!extraProps?.forceDeletion &&
265	      _.has(resource?.metadata, 'deletionTimestamp')) ||
266	    !canCreate;
267	
268	  const content = _.has(resource?.metadata, 'deletionTimestamp')
269	    ? terminatingTooltip || t('Resource is being deleted.')
270	    : '';
271	
272	  return (
273	    <Tooltip
274	      content={
275	        showPermissionTooltip
276	          ? t('You do not have permission to perform this action')
277	          : content
278	      }
279	      trigger={
280	        showPermissionTooltip || (isDisabled && content)
281	          ? 'mouseenter'
282	          : 'manual'
283	      }
284	    >
285	      <Dropdown
286	        data-test={dataTestId || 'kebab-button'}
287	        onSelect={onClick}
288	        ref={dropdownRef}
289	        toggle={{
290	          toggleNode: (
291	            <MenuToggle
292	              ref={dropdownToggleRef}
293	              aria-label="Dropdown toggle"
294	              variant={toggleType === 'Kebab' ? 'plain' : 'default'}
295	              onClick={() => setOpen(!isOpen)}
296	              isExpanded={isOpen}
297	              data-test={dataTestId || 'kebab-button'}
298	              isDisabled={isDisabled}
299	            >
300	              {toggleType === 'Kebab' ? <EllipsisVIcon /> : t('Actions')}
301	            </MenuToggle>
302	          ),
303	          toggleRef: dropdownToggleRef,
304	        }}
305	        isOpen={isOpen}
306	        data-test-id={dataTestId || 'kebab-button'}
307	        popperProps={{
308	          preventOverflow: true,
309	        }}
310	        shouldFocusFirstItemOnOpen={false}
311	      >
312	        <DropdownList>{dropdownItems}</DropdownList>
313	      </Dropdown>
314	    </Tooltip>
315	  );
316	};
317	
318	Kebab.columnClass = 'dropdown-kebab-pf pf-v6-c-table__action pf-v6-u-min-width';
